div.script:
document.addEventListener("DOMContentLoaded", function() {
    const toggleBtn = document.getElementById("togglePasswordBtn");
    const pwdInput = document.getElementById("passwordInput");
    if(toggleBtn && pwdInput) {
        toggleBtn.addEventListener("click", function() {
            const type = pwdInput.getAttribute("type") === "password" ? "text" : "password";
            pwdInput.setAttribute("type", type);
            if (type === "text") {
                toggleBtn.innerHTML = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>';
            } else {
                toggleBtn.innerHTML = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24M1 1l22 22"/></svg>';
            }
        });
    }
});

document.addEventListener("DOMContentLoaded", function() {
    const setupToggle = (btnId, inputId) => {
        const btn = document.getElementById(btnId);
        const input = document.getElementById(inputId);
        if(btn && input) {
            btn.addEventListener("click", function() {
                const type = input.getAttribute("type") === "password" ? "text" : "password";
                input.setAttribute("type", type);
                if (type === "text") {
                    btn.innerHTML = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>';
                } else {
                    btn.innerHTML = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24M1 1l22 22"/></svg>';
                }
            });
        }
    };

    setupToggle("toggleSignupPasswordBtn", "signupPasswordInput");
    setupToggle("toggleSignupConfirmPasswordBtn", "signupConfirmPasswordInput");

    // Confirm password validation
    const pwd = document.getElementById("signupPasswordInput");
    const confirmPwd = document.getElementById("signupConfirmPasswordInput");
    if (pwd && confirmPwd) {
        const validatePassword = () => {
            if(pwd.value !== confirmPwd.value) {
                confirmPwd.setCustomValidity("Passwords Don't Match");
            } else {
                confirmPwd.setCustomValidity('');
            }
        };
        pwd.addEventListener('change', validatePassword);
        confirmPwd.addEventListener('keyup', validatePassword);
    }
});
